#!/bin/bash
# ==============================================================================
# AUTO-GENERATED META-JOB: Medical VQA Pipeline
# Generated by the Pipeline Orchestrator
# ==============================================================================

#SBATCH --job-name=vqa_pipeline
#SBATCH --output=/home/rbalzani/medical-vqa/Thesis/orchestrator_runs/run_20260222_020809/slurm_metajob_%j.out
#SBATCH --error=/home/rbalzani/medical-vqa/Thesis/orchestrator_runs/run_20260222_020809/slurm_metajob_%j.err
#SBATCH -N 1
#SBATCH --gpus=nvidia_geforce_rtx_3090:1
#SBATCH -w faretra
#SBATCH --time=15:00:00
# Send SIGTERM 60s before SIGKILL on timeout, so trap can clean up
#SBATCH --signal=B:TERM@60

# Fail-fast: exit immediately if any command fails
set -e

# ==============================================================================
# GLOBAL ENVIRONMENT
# ==============================================================================
export PYTORCH_CUDA_ALLOC_CONF=expandable_segments:True
export ORCH_OUTPUT_DIR="/home/rbalzani/medical-vqa/Thesis/orchestrator_runs/run_20260222_020809"
# WandB: group all stages of this meta-job under a shared run group in the UI
export WANDB_RUN_GROUP="$(basename \"/home/rbalzani/medical-vqa/Thesis/orchestrator_runs/run_20260222_020809\")"
export WANDB_MODE="${WANDB_MODE:-online}"
export DATA_FILE_OVERRIDE="mimic_ext_stratified_6000_samples.csv"

# ==============================================================================
# ERROR HANDLING & REPORTING
# ==============================================================================
CURRENT_STEP="initializing"
PIPELINE_START=$(date '+%Y-%m-%d %H:%M:%S')

# Snapshot running containers before pipeline starts
PRE_CONTAINERS=$(docker ps -q 2>/dev/null | sort)

cleanup() {
    EXIT_CODE=$?
    TIMESTAMP=$(date '+%Y-%m-%d %H:%M:%S')

    # Kill any Docker containers started during this meta-job
    POST_CONTAINERS=$(docker ps -q 2>/dev/null | sort)
    NEW_CONTAINERS=$(comm -13 <(echo "$PRE_CONTAINERS") <(echo "$POST_CONTAINERS") 2>/dev/null)
    if [ -n "$NEW_CONTAINERS" ]; then
        echo "[$TIMESTAMP] Stopping orphan Docker containers..."
        docker kill $NEW_CONTAINERS 2>/dev/null || true
        sleep 2
    fi

    echo ''
    echo '============================================================'
    if [ $EXIT_CODE -ne 0 ]; then
        echo "[$TIMESTAMP] PIPELINE FAILED at step: $CURRENT_STEP"
        echo "Exit code: $EXIT_CODE"
        echo "Started:   $PIPELINE_START"
        echo "Failed:    $TIMESTAMP"
    else
        echo "[$TIMESTAMP] PIPELINE COMPLETED SUCCESSFULLY"
        echo "Started:  $PIPELINE_START"
        echo "Finished: $TIMESTAMP"
    fi
    echo '============================================================'
}
trap cleanup EXIT
trap 'exit 143' TERM  # Ensure SIGTERM (from SLURM timeout) triggers EXIT trap

# ==============================================================================
# GPU DRAIN HELPER
# ==============================================================================
# Polls nvidia-smi until GPU VRAM usage drops below DRAIN_THRESHOLD_MIB MiB.
# Called between every stage so the next Docker container starts with a clean GPU.
wait_for_gpu_drain() {
    local DRAIN_THRESHOLD_MIB=${1:-2048}  # default: 2 GiB
    local TIMEOUT_S=${2:-120}             # default: 2 min
    local POLL_S=5
    local ELAPSED=0
    local GPU_IDX=${CUDA_VISIBLE_DEVICES:-0}
    echo "[GPU-DRAIN] Waiting for GPU ${GPU_IDX} VRAM to drop below ${DRAIN_THRESHOLD_MIB} MiB (timeout ${TIMEOUT_S}s)..."
    while true; do
        USED_MIB=$(nvidia-smi --query-gpu=memory.used --format=csv,noheader,nounits -i "$GPU_IDX" 2>/dev/null | tr -d " ")
        if [ -z "$USED_MIB" ]; then
            echo "[GPU-DRAIN] nvidia-smi unavailable, skipping drain wait."
            return 0
        fi
        if [ "$USED_MIB" -le "$DRAIN_THRESHOLD_MIB" ]; then
            echo "[GPU-DRAIN] GPU VRAM usage: ${USED_MIB} MiB — OK, proceeding."
            return 0
        fi
        if [ "$ELAPSED" -ge "$TIMEOUT_S" ]; then
            echo "[GPU-DRAIN] WARNING: GPU VRAM still ${USED_MIB} MiB after ${TIMEOUT_S}s. Proceeding anyway."
            return 0
        fi
        echo "[GPU-DRAIN] GPU VRAM usage: ${USED_MIB} MiB — waiting ${POLL_S}s..."
        sleep "$POLL_S"
        ELAPSED=$((ELAPSED + POLL_S))
    done
}

echo "============================================================"
echo "Medical VQA Pipeline - Meta-Job"
echo "Run directory: /home/rbalzani/medical-vqa/Thesis/orchestrator_runs/run_20260222_020809"
echo "Stages: 2"
echo "Dataset override: mimic_ext_stratified_6000_samples.csv"
echo "============================================================"

# ==============================================================================
# STEP 1: VQA Generation
# ==============================================================================
CURRENT_STEP="1 - VQA Generation"
echo "[$(date '+%Y-%m-%d %H:%M:%S')] START: $CURRENT_STEP"

cd "/home/rbalzani/medical-vqa/Thesis/vqa"
bash submit_generation.sh configs/generation/medgemma_1_5.conf

echo "[$(date '+%Y-%m-%d %H:%M:%S')] DONE:  $CURRENT_STEP"

wait_for_gpu_drain

# ==============================================================================
# STEP 2: VQA Evaluation (Judge)
# ==============================================================================
CURRENT_STEP="2 - VQA Evaluation (Judge)"
echo "[$(date '+%Y-%m-%d %H:%M:%S')] START: $CURRENT_STEP"

cd "/home/rbalzani/medical-vqa/Thesis/vqa" || exit 1
PHYS_DIR=$(pwd)

# Load HF_TOKEN from .env if not already set
if [ -z "$HF_TOKEN" ] && [ -f "$PHYS_DIR/.env" ]; then
    echo "  Loading secrets from .env..."
    set -a
    source "$PHYS_DIR/.env"
    set +a
fi

IMAGE_NAME="med_vqa_project:3090"

# Verify Docker image exists
if [[ -z "$(docker images -q "$IMAGE_NAME" 2>/dev/null)" ]]; then
    echo "[ERROR] Docker image '$IMAGE_NAME' not found. Build it first."
    exit 1
fi

echo "  Launching VQA Judge container..."
echo "  Config: configs/judge/hard_coded_judge.conf"

docker run --rm \
    --name "metajob_${SLURM_JOB_ID:-local}_judge" \
    --gpus "device=${CUDA_VISIBLE_DEVICES:-0}" \
    --shm-size=16g \
    -v "$PHYS_DIR":/workspace \
    -v /llms:/llms \
    -e HF_HOME=/llms \
    -e HF_TOKEN="${HF_TOKEN:-}" \
    "$IMAGE_NAME" \
    /bin/bash /workspace/scripts/run_judge.sh "configs/judge/hard_coded_judge.conf"

echo "[$(date '+%Y-%m-%d %H:%M:%S')] DONE:  $CURRENT_STEP"
